/**
 * Internal blocklist last_name gate (Internal policy; FFIEC BSA/AML
 * Examination Manual — internal lists).
 *
 * Scenario #41 of guides/use-cases.md: a transaction whose creditor
 * side carries any active internal-blocklist hit (chargeback fraud
 * rings, repeat-offender lists, ABA-style watchlists, etc.) is
 * blocked. The list itself is operator-curated in the
 * `blocklist_entries` table; `ScreeningEngine.screen_*` populates a
 * `ComplianceScreening` row with one `BlocklistMatch` per hit. Rules
 * read the projected `blocklist_matches[]` on the screening, not the
 * BlocklistCache directly — the cache is the production-path search
 * index, not the rule's data source.
 *
 * Reads `creditor_payment_account.compliance_screenings[]` and looks
 * for any screening whose `blocklist_matches[]` is non-empty.
 * `screening_type` is irrelevant here; the OFAC SDN rule (#11)
 * dispatches on `sanctions_matches[]` for the same reason. When a hit
 * is found, emits a blocked Control per LedgerAccount on the creditor
 * side. cap=0 + is_blocked=true converts to status='rejected' with
 * rejected_rule='internal_blocklist_lastname' at limits-at-entry time.
 */
export const handler = async (input) => {
  const creditor = input.creditor_payment_account;
  if (!creditor) return { ledger_accounts: {} };

  const screenings = creditor.compliance_screenings || [];
  const hit = screenings.some(function (s) {
    const matches = s.blocklist_matches || [];
    return matches.some(function (m) { return m.scope === 'last_name'; });
  });
  if (!hit) return { ledger_accounts: {} };

  const las = creditor.las || [];
  const ledger_accounts = {};
  for (const la of las) {
    ledger_accounts[la.id] = {
      daily_debit_cap: 0,
      daily_credit_cap: 0,
      reason: 'internal_blocklist_lastname',
      block_reason: 'internal_blocklist_lastname',
      is_blocked: true
    };
  }
  return { ledger_accounts };
};
